# Simulate reverting the fix: monkeypatch require_local_uri's logic by reverting
# the DSN/query branches to NOT split on comma (pre-fix behavior).
import re
from urllib.parse import parse_qs, urlparse
from assay_engine import _local
from assay_engine._local import is_loopback_host, NonLocalEndpointError, _authority_hosts, _DSN_TOKEN_RE

# Reverted is_local_socket_path: NO comma guard
def reverted_socket(host):
    if not host: return False
    h = host.strip()
    return h.startswith("/") and not h.startswith("//") and not h.startswith("/\\")

def reverted_require_local_uri(uri, *, what):
    parsed = urlparse(uri); netloc = parsed.netloc; query = parsed.query
    if netloc:
        if "\\" in netloc: raise NonLocalEndpointError("bs")
        for h in _authority_hosts(netloc):
            if "@" in h or not is_loopback_host(h): raise NonLocalEndpointError("a")
        for key in ("host","hostaddr"):
            for val in parse_qs(query).get(key, []):
                # PRE-FIX: whole value, no split
                if not is_loopback_host(val) and not reverted_socket(val):
                    raise NonLocalEndpointError("q")
        return uri
    if "=" in uri:
        for m in _DSN_TOKEN_RE.finditer(uri):
            if m.group(1).strip().lower() in {"host","hostaddr"}:
                raw = m.group(2).strip().strip("'\"")
                # PRE-FIX: whole value, no split
                if not is_loopback_host(raw) and not reverted_socket(raw):
                    raise NonLocalEndpointError("d")
        return uri
    return uri

